<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <div class="btn-group d-flex" role="group">
                @foreach (var mode in Enum.GetValues<ThemeMode>())
                {
                    var isActive = mode == currentMode;
                    <button type="button"
                            class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                            @onclick="() => SetMode(mode)">
                        @mode
                    </button>
                }
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label" for="accent-color">Accent Color</label>
            <div class="d-flex align-items-center gap-3">
                <input type="color" id="accent-color" class="form-control form-control-color"
                       value="@currentAccent" @onchange="SetAccent" />
                <code>@currentAccent</code>
            </div>
        </div>

        <div class="alert alert-info mt-3 mb-0">
            Current: <strong>@Theme.Mode</strong> mode,
            accent <span style="color: @Theme.AccentColor;">■</span> @Theme.AccentColor
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo Theme { get; set; } = ThemeInfo.Default;

    private ThemeMode currentMode;
    private string currentAccent = ThemeInfo.Default.AccentColor;

    [Inject]
    private CascadingValueSource<ThemeInfo> ThemeSource { get; set; } = default!;

    protected override void OnParametersSet()
    {
        currentMode = Theme.Mode;
        currentAccent = Theme.AccentColor;
    }

    private async Task SetMode(ThemeMode mode)
    {
        currentMode = mode;
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentMode, currentAccent));
    }

    private async Task SetAccent(ChangeEventArgs e)
    {
        currentAccent = e.Value?.ToString() ?? ThemeInfo.Default.AccentColor;
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentMode, currentAccent));
    }
}
"}

