namespace sv_be8466a49f9748caa58208bf01d6bb9a.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public record ThemeInfo(ThemeMode Mode, string AccentColor)
{
    public static ThemeInfo Default => new(ThemeMode.Light, "#0d6efd");

    public string CssClass => Mode switch
    {
        ThemeMode.Dark => "theme-dark",
        ThemeMode.System => "theme-system",
        _ => "theme-light"
    };
}

@using sv_be8466a49f9748caa58208bf01d6bb9a.Services

<span class="theme-indicator" title="Current theme">
    <span class="theme-icon">@Icon</span>
    <span class="theme-label">@Theme.Mode</span>
    <span class="accent-dot" style="background-color: @Theme.AccentColor;"></span>
</span>

@code {
    [CascadingParameter]
    private ThemeInfo Theme { get; set; } = ThemeInfo.Default;

    private string Icon => Theme.Mode switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.System => "💻",
        _ => "☀️"
    };
}

.theme-indicator {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.25rem 0.75rem;
    border-radius: 1rem;
    background-color: rgba(0, 0, 0, 0.05);
    font-size: 0.85rem;
}

.accent-dot {
    display: inline-block;
    width: 12px;
    height: 12px;
    border-radius: 50%;
    border: 1px solid rgba(0, 0, 0, 0.15);
}

